const items = $input.all();
const steps = [];

for (const item of items) {
  const d = item.json;

  // Call Gemini for tooltip
  const geminiResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=AIzaSyAhLvtTiOsyY-9AnVwnwbdFpkdz9xAuYtw',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      contents: [{ parts: [{ text: `Create a short 2-sentence tooltip for a product demo step called "${d.title}". Explain what it is and what the user should do. Plain text only.` }] }]
    })
  });
  const tooltip = geminiResp?.candidates?.[0]?.content?.parts?.[0]?.text || 'Click here to continue.';

  // Download image from Drive as base64
  const imageResp = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://drive.google.com/uc?export=download&id=${d.fileId}`,
    encoding: 'arraybuffer',
    returnFullResponse: true
  });
  const imageBase64 = Buffer.from(imageResp.body).toString('base64');

  steps.push({
    step: d.step,
    title: d.title,
    bbox: d.bbox,
    fileId: d.fileId,
    tooltip: tooltip.trim(),
    image: imageBase64
  });
}

return [{ json: { steps } }];

const input = $input.first().json;
const steps = input.steps.sort((a,b) => a.step - b.step);
const stepsJson = JSON.stringify(steps);

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>How to Login — Lockated</title>
<style>
*{margin:0;padding:0;box-sizing:border-box}
body{font-family:-apple-system,sans-serif;background:#111;color:#fff;min-height:100vh;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:20px}
.container{width:min(95vw,900px)}
.progress{width:100%;height:3px;background:#333;border-radius:2px;margin-bottom:12px}
.progress-fill{height:100%;background:#e53935;border-radius:2px;transition:width .4s}
.frame{position:relative;border-radius:12px;overflow:hidden;box-shadow:0 25px 60px rgba(0,0,0,.6)}
.frame img{width:100%;display:block}
.ring{position:absolute;border:3px solid #e53935;border-radius:8px;animation:pulse 1.8s infinite;cursor:pointer}
@keyframes pulse{0%,100%{box-shadow:0 0 0 3px rgba(229,57,53,.3)}50%{box-shadow:0 0 0 8px rgba(229,57,53,.1)}}
.tooltip{position:absolute;background:#fff;color:#111;border-radius:10px;padding:14px 18px;min-width:220px;max-width:300px;box-shadow:0 8px 32px rgba(0,0,0,.4);z-index:100;display:none}
.tooltip.show{display:block;animation:fadein .2s}
@keyframes fadein{from{opacity:0;transform:translateY(4px)}to{opacity:1;transform:translateY(0)}}
.tooltip p{font-size:14px;line-height:1.5;margin-bottom:12px}
.tooltip-footer{display:flex;justify-content:space-between;align-items:center}
.counter{font-size:12px;color:#888}
.btn{background:#e53935;color:#fff;border:none;border-radius:6px;padding:7px 16px;font-size:13px;font-weight:600;cursor:pointer}
.btn:hover{background:#c62828}
.dots{display:flex;gap:8px;justify-content:center;margin-top:14px}
.dot{width:8px;height:8px;border-radius:50%;background:#444;cursor:pointer;transition:all .3s}
.dot.active{background:#e53935;transform:scale(1.3)}
.label{text-align:center;margin-top:10px;font-size:13px;color:#666}
.hint{text-align:center;font-size:11px;color:#444;margin-top:6px}
</style>
</head>
<body>
<div class="container">
  <div class="progress"><div class="progress-fill" id="pf"></div></div>
  <div class="frame">
    <img id="img" src="" alt="">
    <div class="ring" id="ring"></div>
    <div class="tooltip" id="tip">
      <p id="tip-text"></p>
      <div class="tooltip-footer">
        <span class="counter" id="counter"></span>
        <button class="btn" id="btn">Got it →</button>
      </div>
    </div>
  </div>
  <div class="dots" id="dots"></div>
  <div class="label" id="label"></div>
  <div class="hint">← → to navigate</div>
</div>
<script>
const steps=${stepsJson};
let cur=0;
function render(){
  const s=steps[cur];
  document.getElementById('img').src='data:image/png;base64,'+s.image;
  const r=document.getElementById('ring');
  r.style.left=s.bbox.x+'%';r.style.top=s.bbox.y+'%';
  r.style.width=s.bbox.w+'%';r.style.height=s.bbox.h+'%';
  document.getElementById('tip-text').textContent=s.tooltip;
  document.getElementById('counter').textContent='Step '+s.step+' of '+steps.length;
  document.getElementById('label').textContent=s.title;
  document.getElementById('pf').style.width=(s.step/steps.length*100)+'%';
  const t=document.getElementById('tip');
  t.classList.remove('show');
  const below=s.bbox.y+s.bbox.h<65;
  t.style.top=below?(s.bbox.y+s.bbox.h+1)+'%':'auto';
  t.style.bottom=below?'auto':(100-s.bbox.y+1)+'%';
  t.style.left=(s.bbox.x+s.bbox.w>60)?'auto':s.bbox.x+'%';
  t.style.right=(s.bbox.x+s.bbox.w>60)?(100-s.bbox.x-s.bbox.w)+'%':'auto';
  document.getElementById('dots').innerHTML=steps.map((_,i)=>'<div class="dot'+(i===cur?' active':'')+'" onclick="go('+i+')"></div>').join('');
  setTimeout(()=>t.classList.add('show'),400);
}
function go(i){if(i>=0&&i<steps.length){cur=i;render();}}
document.getElementById('ring').onclick=()=>document.getElementById('tip').classList.add('show');
document.getElementById('btn').onclick=()=>{
  if(cur<steps.length-1)go(cur+1);
  else{document.getElementById('tip-text').textContent='🎉 Login flow complete!';document.getElementById('btn').textContent='Restart';document.getElementById('btn').onclick=()=>go(0);}
};
document.addEventListener('keydown',e=>{
  if(e.key==='ArrowRight')go(cur+1);
  if(e.key==='ArrowLeft')go(cur-1);
});
render();
</script>
</body>
</html>`;

const buf = Buffer.from(html, 'utf8');
return [{binary:{data:{data:buf.toString('base64'),mimeType:'text/html',fileName:'how-to-login.html'}}}];

